"use strict";parserFactory.register("soafp.com",()=>new SoafpParser);class SoafpParser extends WordpressBaseParser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector(".novel-chapter-list");return util.hyperlinksToChapterList(t)}extractAuthor(){return"Soafp"}extractSubject(e){return[...e.querySelectorAll("#novel-genres-list a"),...e.querySelectorAll("#novel-tags-list a")].map(e=>e.textContent).join(", ")}extractDescription(e){return e.querySelector(".entry-synopsis").textContent.trim()}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"button"),super.removeUnwantedElementsFromContentElement(e)}findCoverImageUrl(e){return util.getFirstImgSrc(e,".post-thumbnail")}}